/**
 * @summary Create an operational task
 */
export const CreateOperationalTaskBody = zod.object({
  departmentId: zod.number(),
  name: zod.string(),
  description: zod.string().optional(),
  type: zod.enum(["recurring", "one_time"]),
  frequency: zod
    .union([
      zod.enum([
        "daily",
        "weekly",
        "bi_weekly",
        "monthly",
        "quarterly",
        "bi_annual",
        "annual",
        "multi_year",
      ]),
      zod.null(),
    ])
    .optional(),
  nextDueDate: zod.string().describe("YYYY-MM-DD"),
  ownerId: zod.number().nullish(),
  controlCategory: zod.string().nullish(),
  checklist: zod
    .array(
      zod.object({
        id: zod.string(),
        text: zod.string(),
        done: zod.boolean(),
        assigneeId: zod.number().nullish(),
        assigneeName: zod.string().nullish(),
        dueDate: zod.string().nullish().describe("YYYY-MM-DD"),
        completedAt: zod
          .string()
          .nullish()
          .describe(
            "ISO timestamp captured the moment `done` flipped from false to true. Cleared when the item is unchecked.\n",
          ),
      }),
    )
    .optional(),
});

